var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"어릴 때, 숲에 들어갔다가 굶주린 곰이랑 마주친 적이 있었어.","JPN":"小さい頃、森に入って飢えたクマと遭遇したことがあった。","ENG":"When I was young, I went into the woods and ran into a starving bear.","TWN":"小時候去森林裡玩，我遇到了饑餓的熊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"신기하게도 하나도 무섭지 않았어.","JPN":"でも不思議なことに、ひとつも怖くなかった。","ENG":"Strange as it is, I wasn't frightened at all.","TWN":"神奇的是我一點都不害怕。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"이, 이쪽으로 온다!!","JPN":"む、向かってくるぞ！！","ENG":"H-he’s coming this way!","TWN":"往，往這邊來了！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대체 저 괴물은 뭐야! 혼자서 싸우는데 왜 상처 하나 입지 않냐고!!","JPN":"なんだあの化け物は！　たった一人で戦っているというのに、なんで傷ひとつ付かないんだ！！","ENG":"What is that monster?! He’s fighting alone, how is he unscathed?!","TWN":"那個怪物究竟是什麼東西！為什麼明明孤身一人，卻還是毫髮無傷！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원자님! 어디 계십니까! 구원자님!!","JPN":"救世主様！　どこですか！　救世主様！！","ENG":"Savior! Where are you, Savior?!","TWN":"救贖者大人！您在哪裡！救贖者大人！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"기억해 보면 예전부터 그랬어.","JPN":"思い返せば、昔からそうだった。","ENG":"I think it's always been like that.","TWN":"仔細想想，從以前開始就一直如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"칼을 들고 있으면 사나운 짐승도, 어떤 괴물도 무섭지 않았거든.","JPN":"剣さえあれば、狂暴な獣も、どんな怪物も怖くなかった。","ENG":"With a sword in my hand, no beast or monster could ever frighten me.","TWN":"只要我手中有劍，不管是猛獸還是怪物，我便都不會害怕。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"알렌은 그걸 타고난 본능 때문이라고 가르쳐 줬어.","JPN":"アレンは、それは生まれつきの本能のせいだと教えてくれた。","ENG":"Allen told me that I was born with certain instincts.","TWN":"艾倫說這是與生俱來的本能。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"넌 칼을 들고 있는 동안에는, 상대를 이길 수 있을지 없을지 직감적으로 알아챈다면서.","JPN":"僕は剣を持っている間は、相手に勝てるかどうかが直感的にわかっしまうと。","ENG":"That, while holding a sword, I instinctively know whether I can beat the enemy or not.","TWN":"他還說我拿著劍的時候，直覺上就會知道是否能夠戰勝對手。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"산개해! 비공정이 추락한다!","JPN":"散開しろ！　飛行艇が落ちてくるぞ！","ENG":"Disassemble! The aircraft is crashing!","TWN":"散開！飛空艇要墜落了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"골렘도 전멸했어! 이제 끝이야……! 끝이라고!!","JPN":"ゴーレムも全滅だ！　もう終わりだ……！　おしまいだ！！","ENG":"All golems down! We're done for... We’re doomed!","TWN":"泥人也全軍覆沒了！現在完了……！完了！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG_02"},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"내게는 필요없는 힘이었지만, 적어도 누군가를 지키는 데 쓸 수는 있었어.","JPN":"僕には必要ない力だったけど、この力で少なくとも誰かを守ることはできた。","ENG":"I didn't need that power, but I could at least use it to protect others.","TWN":"雖然我不需要這樣的力量，但至少我可以用它來保護某個人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 구원자가 되어 사람들을 지키겠다고 결심했지만…….","JPN":"だから救世主になって、みんなを守るって決めたのに……","ENG":"Hence, I decided to be the Savior, to protect everyone...","TWN":"所以我才下定了決心，成為保護人們的救贖者……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"큭……. 하아…… 하……","JPN":"くっ……はぁ……はぁ……","ENG":"Kgh...! *Huff* *Huff*","TWN":"咳……哈啊……哈……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌……?","JPN":"アレン……？","ENG":"Allen...?","TWN":"艾倫……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"정신이 들었나……. 현자의 비약을 남겨 두길 다행이군.","JPN":"意識が戻ったか……賢者の秘薬を残しておいたのが幸いだった。","ENG":"You're awake... It was a wise decision to save up on the Sage's potions...","TWN":"你醒了……幸虧智者的秘藥還有剩。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌, 등에 피가 이렇게나 많이…….","JPN":"アレン、背中に血がこんなに……","ENG":"Allen, there's so much blood on your back...","TWN":"艾倫，你的後背流了很多血……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"내가 얼마나 쓰러져 있었던 거야? 마왕과 검을 맞댄 다음에 분명…….","JPN":"僕はどのくらい倒れてたの？　魔王と剣を交えて、そのあとは確か……","ENG":"How long was I out? I remember crossing blades with the Demon Lord, then...","TWN":"我暈倒多久了？在與魔王的劍碰上之後，我明明……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"미안하지만, 설명할 시간이 없어.","JPN":"悪いが、説明している暇はない。","ENG":"I'm sorry, but there's no time to explain.","TWN":"對不起，沒時間跟你解釋了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"나는, 괜찮으니까…… 전하를……","JPN":"私は、大丈夫だ……それよりも殿下を……","ENG":"I'll be fine... Take care of His Highness...","TWN":"我，沒關係……保護殿下……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌! 내 말 들려, 알렌?! 어서 대답해!!","JPN":"アレン！　聞こえる、アレン！？　返事して！！","ENG":"Allen! Can you hear me, Allen? Answer me!","TWN":"艾倫！你能聽見我說話嗎，艾倫？！回答我！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐 하고 있나! 고개를 들어라, 평민!","JPN":"何をしている！　顔を上げろ、平民！","ENG":"What do you think you're doing? Put your head up, peasant!","TWN":"你在幹什麼！抬起頭來，平民！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어서 검을 잡아라! 알렌 경이 추모를 부탁하더냐!","JPN":"早く剣を取れ！　アレンは自分を悼むよう頼んだか！","ENG":"Wield your sword, now! Sir Allen did not ask you to mourn!","TWN":"拿起你的劍！艾倫卿要求你悼念了嗎！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저, 전하……","JPN":"で、殿下……","ENG":"Y-Your Highness...","TWN":"殿，殿下……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯도 쓰러졌다. 싸울 수 있는 사람은 이제……!","JPN":"シャーロットも倒された。戦えるのはもう……！","ENG":"Carlota is also down. You are the only one who can now fight against–","TWN":"夏洛特也倒下了。如今能夠戰鬥的人就只剩你……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"크윽!? 쿨럭……!","JPN":"くうっ！？　ゴホッ……！","ENG":"Krrgh...! *Cough...!*","TWN":"咳呃！？咳咳……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하!!","JPN":"殿下！！","ENG":"Your Highness!","TWN":"殿下！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"구도자의 방계치고는 제법이었다.","JPN":"求道者の傍系にしては、悪くない実力だった。","ENG":"That was quite impressive, coming from mere collateral of the Seeker of Truth.","TWN":"以求道者的旁系來說，你還算不錯。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L45_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"하지만 너희의 피에 흐르는 것이 얼마나 역겨운 악취를 풍기는지는 몰랐던 모양이군.","JPN":"だが、その身に流れる血がどれほどひどい悪臭を放っているかは知らなかったようだな。","ENG":"Little did you know that what flows in your bloodline reeks of stench.","TWN":"不過你好像不知道，你們血液中流淌的東西散發著多麼難聞的惡臭。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민…… 아직, 늦지 않았다…… 너라도……","JPN":"平民……まだ、間に合う……貴様だけでも……","ENG":"Peasant... It's not too late... You...","TWN":"平民……還，來得及……只要你……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하, 일어나세요! 전하!!","JPN":"殿下、しっかりしてください！　殿下！！","ENG":"Your Highness! Get up, Your Highness!","TWN":"殿下，快起來！殿下！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"무력한 양 떼 속에 파묻혀 지내느라 자기 본분을 잊었나, 구원자.","JPN":"非力な羊の群れに長く埋もれていたせいで、自分が誰かを忘れてしまったのか、救世主。","ENG":"Did you forget your true self, Savior? Being surrounded by these helpless lambs?","TWN":"在軟弱無力的羊群中生活久了，你忘記自己的本分了嗎，救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그 제복은 오직 이 세계에 선택 받은 자만이 갖춰 입을 수 있는 것.","JPN":"その礼装は、この世界で選ばれし者だけが着られるものだ。","ENG":"That uniform is only given to those who are chosen by this world.","TWN":"只有被這個世界選中的人才能擁有並穿上那套制服。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"늑대가 사라진 지금, 마왕을 무찌를 권리는 이 세계에서 오직 너에게만 허락된 것이다.","JPN":"狼が消えた今、魔王を倒すことはこの世界でたった一人、そなただけに許されている。","ENG":"With the Wolf gone, you are the sole being in this world who is capable of defeating the Demon Lord.","TWN":"現在狼消失了，這個世界就只剩你擁有打敗魔王的權利。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이건…… 구원의 지팡이?","JPN":"これは……救世の杖？","ENG":"That's... the Staff of Resurrection.","TWN":"這是……救贖之杖？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그렇다면, 루크레시아까지…….","JPN":"ということは、ルクレシアも……","ENG":"Then... Lucrecia...","TWN":"那麼，連露可蕾西亞……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"쓰러진 너를 데리고 도망치려 했다.","JPN":"倒れたそなたを背負って逃げようとしたのだ。","ENG":"She tried to run away, carrying you while you were unconscious.","TWN":"你在說那個試圖帶你逃跑的女人嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"마지막에는 날 섬길 테니 구원자를 살려 달라고 빌다가 내 목을 노리더군.","JPN":"最後には我に忠誠を誓う代わりに救世主の助命を請うふりをし、我を殺そうとした。","ENG":"She swore to serve me, begging me to spare you... then she came for my throat.","TWN":"她發誓侍奉我，求我饒你一命，結果卻突然跳起來，企圖砍下我的腦袋。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그래서 베었다. 비굴하고 추한 본성을 지닌 여자였어.","JPN":"だから斬り捨てた。卑屈で醜い本性を持つ女だった。","ENG":"So I killed her. A fool and a coward she was.","TWN":"所以我殺了她，那個本性卑賤骯髒的女人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신은…….","JPN":"あなたは……","ENG":"You...","TWN":"你……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님!! 도와 주세요!","JPN":"救世主様！！　お助けください！","ENG":"Savior! Help!","TWN":"救贖者大人！！幫幫我！！"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자는 어디 간 거야! 제발 저 괴물 좀 어떻게 해 줘!!","JPN":"救世主はどこに行ったんだよ！　あの化け物をなんとかしてくれよ！！","ENG":"Where is the Savior? Please, do something!","TWN":"救贖者大人去哪兒了！求求您，快想辦法解決那個怪物！！"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님!! 우리에게 구원을!","JPN":"救世主様！！　我々に救いを！","ENG":"Savior! Deliver us!","TWN":"救贖者大人啊！！請予以我們救贖吧！"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아아아아아아!!","JPN":"はああああああっ！！","ENG":"HAAAAA!!","TWN":"哈啊啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그렇군. 이것이 네 본래 실력인가.","JPN":"そうか。これがそなたの真の実力か。","ENG":"I see. So this is your true power.","TWN":"啊，這就是你本來的實力嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L20_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"하지만 그것만으로는 아직 부족하다.","JPN":"しかしこれだけではまだ足りぬ。","ENG":"But that isn’t enough, is it?","TWN":"不過光是這樣還不夠。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"현자가 충고해 주지 않았나? 이 세계는 너를 뒷받침해 주기엔 너무나도 미숙하다고.","JPN":"賢者が忠告しなかったか？　この世界はそなたを活かすにはあまりにも未熟だと。","ENG":"Didn't the Sage warn you? This world is too weak to contain you.","TWN":"智者不是給過你忠告了嗎？這個世界太不成熟，無法支撐你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"닥쳐어어어어어!!","JPN":"黙れぇぇぇぇ！！","ENG":"Shut up!","TWN":"閉嘴啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아……. 하…… 하아……","JPN":"はあ……はぁ……はあ……","ENG":"Hngh… Haa… Ngh…","TWN":"哈啊……哈……哈啊……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"틀렸어. 간신히 움직임을 따라잡았는데……. 저쪽은 여유가 넘쳐.","JPN":"ダメだ。こっちは動きについていくのがやっとだっていうのに……向こうは余裕だ。","ENG":"This isn't going to work. I can barely keep up with him... and he’s not tired at all.","TWN":"從他從容的動作看，就這麼……結束了嗎。我勉強才能跟上……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어떻게 해야 하지? 어떻게 해야 이길 수 있는 거야?","JPN":"どうしよう？　どうすれば勝てる？","ENG":"What should I do? How can I win against him?","TWN":"我該怎麼辦？怎樣才能贏他？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아니, 어쩌면…… 처음부터 이길 수 없는 싸움이었던 건……","JPN":"いや、もしかすると……初めから勝ち目なんてない戦いだったんじゃ……","ENG":"No, maybe... this was a fight meant to be lost...","TWN":"不，或許……從一開始這就是一場註定贏不了的戰鬥嗎……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"……결국 넘어서지 못하는군.","JPN":"……結局は超えられぬか。","ENG":"...So you cannot surpass me.","TWN":"……你終究還是無法超越我啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"인구의 8할을 정리해도 이 정도라니. 쓸데없는 피만 보았다.","JPN":"人口の8割を始末してもこの程度とは。無駄な血を見た。","ENG":"I destroyed 80 percent of your population, and this is it? What useless bloodshed.","TWN":"哪怕我滅絕了八成的人口，你還是這種水準。簡直就是白費功夫。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신은 왜…… 그런 힘을 가지고도……!","JPN":"あなたはどうして……そこまでの力がありながら……！","ENG":"You... Why...! With that much power, why...!","TWN":"你……擁有那樣的力量，為什麼……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"동료들을 잃어 분노하는가, 구원자.","JPN":"仲間を失って憤っているのか、救世主。","ENG":"Does the loss fuel your rage, Savior?","TWN":"為失去同伴感到憤怒嗎，救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"뭐……?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"너의 동료들을 앗아간 나에게 분노하고 있냐는 뜻이다.","JPN":"そなたの仲間の命を奪った我に憤っているのかと聞いているのだ。","ENG":"I asked if you are furious because I took the lives of your friends.","TWN":"我在問你，對奪走你同伴生命的我感到憤怒嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그건……! 그건 당연하잖아! 다들 좋은 사람들이었으니까!","JPN":"それは……！　そんなの当たり前だろう！　みんな良い人たちだったんだ！","ENG":"That's...! Of course! They were all good people!","TWN":"那……！那當然！大家都是好人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그런데 대체……!","JPN":"それなのにいったい……！","ENG":"And still, why would you...!","TWN":"到底……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"대체 뭘 위해서 이렇게까지 하는 거야! 어째서!!","JPN":"いったい何のためにここまでするんだ！　どうして！","ENG":"What's the point of all this?! Why?!","TWN":"你到底為什麼要做出這種事！為什麼！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"어리석은 소리. 세계의 멸망은 필연적이다.","JPN":"愚問だな。世界の滅亡は必然だ。","ENG":"Fool. The end is inevitable.","TWN":"真是愚蠢。世界的滅亡是必然的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"나를 막는다고 한들, 이 세계에 예정된 멸망은 결국 도래할 테니.","JPN":"我を食い止めることができても、この世界には必ず予定された滅亡が到来する。","ENG":"Even if you succeed in taking me down, this world is bound to be destroyed.","TWN":"就算你阻止了我，這個世界所定下的滅亡也終將到來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이제 와서 그런 거짓말을……","JPN":"今更そんな嘘を……","ENG":"After everything, you think...","TWN":"事到如今，你為什麼要說這種謊話……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그런다고 믿을 것 같아?!","JPN":"そんなこと言われたって、信じられるかよ！？","ENG":"You think I would believe that?!","TWN":"你覺得我會相信嗎？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"아아, 그렇군.","JPN":"ああ、そうか。","ENG":"Ah, right.","TWN":"啊……是啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그녀의 눈에 비친 나도 너와 같이 비참해 보였겠지…….","JPN":"彼女の目に映る我もまた、今のそなたのように惨めだったのだろう……","ENG":"In her eyes, I would have looked as pitiful as you look right now...","TWN":"她眼中的我，應該也和你一樣悲慘吧……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"좋다, 구원자.","JPN":"よかろう、救世主。","ENG":"Very well, Savior.","TWN":"很好，救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"진정으로 네가 동료들을 잃었다는 사실에 분노한다면.","JPN":"心からそなたの仲間の死に憤っているのなら。","ENG":"If you truly are enraged at the loss of your beloved ones...","TWN":"如果你真的為失去同伴感到憤怒。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"나를 죽여라. 저항은 하지 않으마.","JPN":"我を殺せ。抵抗はしない。","ENG":"Kill me. I will not resist.","TWN":"那就殺死我吧，我不會反抗。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그게…… 갑자기 무슨……","JPN":"それは……いきなりどういう……","ENG":"What are you... All of a sudden...","TWN":"突然……你在打什麼主意……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"도발하는 건가? 아니면, 조롱하려고?","JPN":"挑発しているのか？　それとも、からかっているのか？","ENG":"Are you taunting me? Is this mockery?","TWN":"你這是在挑釁我嗎？還是在諷刺我？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"기약도 희망도.","JPN":"約束も希望も。","ENG":"Neither promise nor hope.","TWN":"我只是厭倦了沒有承諾，沒有希望……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"이제는 이유도 잊어 버린 복수에 지쳤을 뿐이다.","JPN":"もはや理由さえも忘れた復讐に疲れただけだ。","ENG":"I’m tired of this vengeance that lost its meaning.","TWN":"如今連理由也失去了的復仇而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"마지막으로 한 번은 적의 손에 쓰러지길 바랐지만…….","JPN":"最後に一度くらいは敵の手によって倒れることを願ったが……","ENG":"I dearly wished to die by the hands of a foe...","TWN":"不過我仍舊希望最後能夠死在敵人的手裡……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"내 욕심이 너무 과했던 거겠지.","JPN":"それも我の行き過ぎた願いだったのだろう。","ENG":"But I suppose I was asking for too much.","TWN":"但或許是我太貪心了吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"대체 뭐야? 그래서 죽고 싶다고?","JPN":"どういうことだ？　だから死にたいって？","ENG":"So what? You want to die now?","TWN":"究竟是怎麼回事？所以你想死嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그럼 처음부터 죽어 버리면 됐잖아!","JPN":"なら最初から死ねばよかったじゃないか！","ENG":"Then why didn't you just let yourself die in the first place?!","TWN":"那你一開始就去死就好了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"세계의 규칙은 네 상상보다 편협하기 때문이지.","JPN":"世界のルールはそなたが思うより融通が利かないからだ。","ENG":"Because the rules of the world are far more biased than you can imagine.","TWN":"呵呵呵呵……世界的規則比你想像得要狹隘，救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"가령, 나를 죽였을 때 네가 마왕의 위계를 계승하는 것처럼.","JPN":"例えば、そなたが我を殺したあかつきには魔王の位階を継承するようにな。","ENG":"Such as the fact that you will assume the title of Demon Lord once you defeat me.","TWN":"就像，殺死我時，你會繼承魔王的位階一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"뭐라고……?","JPN":"何だって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"빛이 있으면 그림자가 지듯이, 마왕의 위계 역시 이 망가진 세계를 지탱하는 근간 중 하나.","JPN":"光があれば影ができるように、魔王の位階もまた、この壊れた世界を支える根幹のひとつ。","ENG":"With light comes darkness. The Demon Lord is also one of the pillars that maintain the balance of this world.","TWN":"就像有光就有暗影一樣，魔王的位階也是支撐這個破敗世界的根基之一。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"한 세계의 기대를 짊어진 대적자가 아니라면 감당할 재목은 없다.","JPN":"一つの世界の期待を背負った敵対者以外、担える者はいない。","ENG":"No one will be able to bear the weight, if not for the Antagonist praised by the whole world.","TWN":"只有背負一個世界期待的敵對者才能勝任。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아까부터 허무맹랑한 소리나 늘어 놓기나 하고!","JPN":"さっきからでたらめばかり言って！","ENG":"You're rambling nonsense!","TWN":"從剛才開始，你就一直在胡說八道！"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"내가 마왕이 된다고? 협박이라도 하려는 거야?","JPN":"僕が魔王になるだって？　それは脅しのつもりか？","ENG":"Me becoming the Demon Lord? Are you trying to threaten me or something?","TWN":"我會成為魔王？你是想威脅我嗎？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"마왕의 위계를 계승한다면.","JPN":"魔王の位階を継承すれば。","ENG":"If you take on the role...","TWN":"繼承魔王的階位。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"동료들만은 되살릴 수 있다.","JPN":"仲間だけは生き返らせることができよう。","ENG":"You can bring your people back to life.","TWN":"就能救活你的那些同伴。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"너희들이 심복이라고 부르던 나의 동료들처럼.","JPN":"そなたらが側近と呼んでいた我の仲間のようにな。","ENG":"Like my soldiers, whom you have been calling my henchmen.","TWN":"就像你們稱之為心腹的我的同伴一樣。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"되살려……?","JPN":"生き返らせる……？","ENG":"Bring back...?","TWN":"復活……？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"물론 그 대가로 너는 저들에게 크나큰 증오를 사겠지.","JPN":"もちろんその代償として、そなたはあの者たちから多くの憎しみを買うだろう。","ENG":"Of course, they will despise you. A price to pay for bringing them back.","TWN":"當然，其代價是你被他們深深地憎恨。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L32_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"나 역시 한때는 그 증오를 짊어질 자신이 있었지만……","JPN":"我もまた、かつてはその憎しみを背負っていく自信があったが……","ENG":"There was a time when I thought I was capable of handling the hatred...","TWN":"曾經我也有信心背負那種憎恨……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"결국 모두 만용에 불과했다.","JPN":"結局のところ、すべては蛮勇に過ぎなかった。","ENG":"But I was mistaken.","TWN":"但到頭來全都只是我的匹夫之勇而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그럼에도 원한다면 마왕의 위계를 계승해라, 구원자.","JPN":"それでもなお望むなら、魔王の位階を継承しろ、救世主。","ENG":"If you are still willing to save your people, be the successor to this role, Savior.","TWN":"哪怕如此你也願意的話，那就繼承魔王的階位吧，救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아아아!","JPN":"ワアアアアア！","ENG":"*Cheer*","TWN":"噢噢噢噢噢！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님께서 우리를 지켜 주신다! 이제 우리 모두 살았어!","JPN":"救世主様が守ってくださる！　我々は皆助かるんだ！","ENG":"The Savior protected us! We are saved!","TWN":"有救贖者大人保護我們！現在我們都有救了！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원의 맹세를 기억하세요.","JPN":"救いの誓いを思い出してください。","ENG":"Remember the oath of salvation.","TWN":"請記住救贖的誓言。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님께서는 꼭 이 세계를 구해 주실 겁니다. 저를 구원해 주셨듯이.","JPN":"救世主様は必ずこの世界を救ってくださいます。私を救ってくださったように。","ENG":"You will save our world, Savior. Just as you have saved me.","TWN":"救贖者大人一定會拯救這個世界，就像曾經救贖我那樣。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"정말 마왕과 싸워 이길 수 있는 걸까……?","JPN":"本当に魔王と戦って勝てるのか……？","ENG":"Can we really win against the Demon Lord...?","TWN":"我們真的能戰勝魔王嗎……？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님이 계신다면 가능할 거야! 내가 전쟁터에서 이 두 눈으로 직접 봤거든!","JPN":"救世主様がいてくださればできる！　戦場でこの目で直接見たんだ！","ENG":"With the Savior by our side, I'm sure we can! I saw him in battle, with my own eyes!","TWN":"有救贖者大人在就能！我在戰場上親眼看到了！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠. 이제 와서 그 제복의 무게를 실감한 거냐, 평민. 여전히 미숙하군.","JPN":"ふむ。今になってやっとその礼装の重みを実感したのか、平民。相変わらずの未熟さだ。","ENG":"Hmm. So you finally realized what you've gotten yourself into, peasant. So naive.","TWN":"哼，現在你終於切身感受到那套制服的重量了，平民。不過還是不熟練啊。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네가 구원자의 길을 걷는 것이 아니다. 철지난 전설 따위에 목매달 셈인가?","JPN":"貴様が救世主の道を踏襲するのではない。あの古い伝説などにしがみついてどうする？","ENG":"It is not that you are walking the path of the Savior. Don't get hung up on an old myth.","TWN":"並不是你走在救贖者之路上。那只不過是老掉牙的傳說罷了。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니, 네가 걷는 길을 구원자의 길로 만들어라.","JPN":"だから、貴様の歩む道を救世主の道としろ。","ENG":"You shall make the path you walk into the path of the Savior.","TWN":"你要明白，是你走的路，才稱之為救贖者之路。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님 만세! 전하 만세!","JPN":"救世主様万歳！　殿下万歳！","ENG":"Long live the Savior! Long live His Highness!","TWN":"救贖者大人萬歲！殿下萬歲！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"부디 무사히 돌아오세요! 매일 기도드릴게요!","JPN":"無事にお帰りください！　毎日お祈りします！","ENG":"Please come back safe! We will pray for you every day!","TWN":"請一定要平安回來！我們會每天祈禱的！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"언젠가는 반드시 널 넘어서겠어. 구원자.","JPN":"いつの日か必ずそなたを越えてみせる。救世主。","ENG":"Someday, I swear I will beat you. Savior.","TWN":"總有一天我要超越你，救贖者。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그러니 그 때까지는 살아 있어야 해.","JPN":"だから、その時までは生きていろ。","ENG":"So make sure you stay alive until then.","TWN":"所以，你一定要活到那個時候。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원자님께서 와 주신 덕분에 아무도 부상을 입지 않았습니다!","JPN":"救世主様が来てくださったおかげで、誰も怪我をせずに済みました！","ENG":"Thanks to you, Savior, no one was hurt!","TWN":"托救贖者大人的福，這次沒有一個人受傷！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 구원자님! 덕분에 가족들과 다시 만날 수 있게 됐어요!","JPN":"ありがとうございます、救世主様！　おかげさまで家族とまた会えます！","ENG":"Thank you, Savior! If it wasn't for you, I wouldn't have been able to reunite with my family!","TWN":"謝謝您，救贖者大人！多虧了您，我們才能再次見到家人！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"설령 이 세상에 구원이란 게 없더라도……","JPN":"たとえこの世界に救いというものが無かったとしても……","ENG":"Even if there is no such thing as salvation in this world...","TWN":"沒錯，就算世界上沒有所謂的救贖……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"누군가는 그들을 도울 수 있을지도 모르지.","JPN":"誰かは人々を救うことができるかもしれない。","ENG":"Someone may be able to help the people.","TWN":"或許也有那麼一個人可以幫助大家。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……나는.","JPN":"……僕は。","ENG":"...I","TWN":"……就是我。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"큭, 잠시 기절했나……","JPN":"クッ、気絶していたのか……","ENG":"Kgh, I must have fainted...","TWN":"咳，我暈倒了嗎……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네헤모트! 네헤모트는 어떻게 되었나!","JPN":"ネヘモト！　ネヘモトはどうなった！","ENG":"Nehemoth! What happened to Nehemoth?","TWN":"貝赫莫特！貝赫莫特呢！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"진정하시죠, 전하. 네헤모트는 이 곳에 없습니다.","JPN":"落ち着いてください、殿下。ネヘモトはここにはいません。","ENG":"Calm down, Your Highness. Nehemoth is not here.","TWN":"請冷靜點，殿下。貝赫莫特不在這裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐라? 그렇다면 그 평민이 해냈다고?","JPN":"なに？　ならばあの平民がやったのか？","ENG":"What? Are you saying that the peasant did it?","TWN":"什麼？那個平民做到了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……아니, 무언가 이상하지 않느냐. 알렌 경.","JPN":"……いや、何かがおかしいと思わないか。アレン。","ENG":"...No, that's not it. Something feels strange, Sir Allen.","TWN":"……不，你不覺得有種奇怪的感覺嗎，艾倫卿。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대도 나와 같이 죽음이 임박했다고 느꼈을 것이다.","JPN":"そなたも私と同じく、死を目前に感じていたはずだ。","ENG":"I know you felt that death was upon you, just like I did.","TWN":"你應該也和我一樣，有瀕臨死亡的感覺吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 지금은 뭔가 다르다. 오히려……","JPN":"しかし、今は何かが違う。むしろ……","ENG":"But something is different now. It's rather...","TWN":"但是現在有什麼不一樣了，反而……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……자신의 것이 아닌 힘이 몸 속에 흐르는 기분이시군요.","JPN":"……自分のものではない、何かしらの力が体内に流れている感覚でしょうか。","ENG":"...You feel a surge of power flowing inside you, a power that is not yours.","TWN":"……有種不是自己的力量在身體裡流淌的感覺。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"저 역시 그렇습니다.","JPN":"私も同じです。","ENG":"I feel the same, Your Highness.","TWN":"我也這麼覺得。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하!","JPN":"殿下！","ENG":"Your Highness!","TWN":"殿下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님……? 부활의 지팡이도 빼앗겼을 텐데, 이게 어떻게 된 일이죠?","JPN":"救世主様……？　復活の杖も奪われたのに、どうなっているのですか？","ENG":"Savior...? What happened? The Demon Lord took the Staff of Resurrection...","TWN":"救贖者大人……？復活之杖被搶走了！……怎麼會這樣？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민, 어서 대답해라. 무슨 요술을 부린 거지?","JPN":"平民、さっさと答えろ。どんな手を使ったんだ。","ENG":"Answer, peasant. What witchcraft is this?","TWN":"回答我，平民。你用了什麼妖術？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하, 저는…….","JPN":"殿下、僕は……","ENG":"Your Highness, I...","TWN":"殿下，我……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어서 대답하라 하지 않았느냐!","JPN":"早く答えろと言ったはずだ！","ENG":"Answer me!","TWN":"快回答我！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하, 고정하십시오!","JPN":"殿下、落ち着いてください！","ENG":"Your Highness! Wait–","TWN":"殿下，請您冷靜點！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ありません。","ENG":"...Forgive me.","TWN":"……非常抱歉。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어쩔 수 없었어요.","JPN":"仕方がなかったんです。","ENG":"It had to be done.","TWN":"我沒有……其他辦法。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"콜록……! 콜록!!","JPN":"ゴホッ……！　ゴホッ！！","ENG":"*Cough...!* *Cough!!*","TWN":"咳咳……！咳咳！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"중간부터 갑자기 레이 선배가 된 것 같았어……. 어떻게 된 거야? ","JPN":"途中からまるで自分がレイ先輩になったような気分だったよ……いったいどうなってるの？ ","ENG":"I felt as if I was Ray midway through... What happened?","TWN":"我看到一半的時候，感覺自己突然變成雷伊前輩了……這是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네. 느끼셨던 그대로입니다. 확실히 아슬아슬했어요.","JPN":"はい、お感じになった通りです。今のは危なかったですよ。","ENG":"You felt it right. It was close.","TWN":"呼，就是你感覺到的那樣。確實很驚險。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"마지막에는 저희 모두 환각을 일으킨 장본인의 의식에 삼켜질 뻔했거든요.","JPN":"最後は僕たち全員が幻覚を引き起こした張本人の意識に呑み込まれかけましたからね。","ENG":"We almost got devoured by the consciousness of whoever made this hallucination.","TWN":"最後我們差點被製造這個幻覺的罪魁禍首的意識給吞噬了呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희가 상당히 과하게 몰입하길 바라셨나 보네요. <color=#ffd34c>네헤모트</color> 씨.","JPN":"僕たちが過度にのめり込むのを願っていたみたいですね。<color=#ffd34c>ネヘモト</color>さん。","ENG":"It seems like you wanted us to be immersed, <color=#ffd34c>Mr. Nehemoth</color>.","TWN":"這就是你的意圖嗎，<color=#ffd34c>貝赫莫特</color>？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……그럴 의도는 아니었지만.","JPN":"……そういうつもりはなかったんだけど。","ENG":"...I didn't mean to.","TWN":"……我不是有意如此。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"다시 뵙게 되었네요. 세 분 모두.","JPN":"もう一度会いましたね、三人とも。","ENG":"Hello again, you three.","TWN":"又見面了，三位。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};